def parse(begin, end, instr):
    cur = begin
    results = []
    while cur < end:
        c = instr[cur]
        if c == ",":
            results.append(instr[begin:cur])
            cur += 1
            begin = cur
            continue
        elif c == "(":
            num_open = 1
            cur += 1
            key = instr[begin : cur - 1]
            begin = cur
            while num_open != 0:
                if instr[cur] == "(":
                    num_open += 1
                if instr[cur] == ")":
                    num_open -= 1
                cur += 1
            key += "()"
            subtree = parse(begin, cur - 1, instr)
            results.append({key: subtree})
            begin = cur + 1
        cur += 1
    return results


def main(instr):
    full = parse(0, len(instr), instr)
    print(pprint(full))


if __name__ == "__main__":
    main(clang_passes)
